queries.sphinxql:
drop table if exists t;
CREATE TABLE t (
f text,
m multi,
v FLOAT_VECTOR
    KNN_TYPE='hnsw'
    HNSW_SIMILARITY='cosine'
    MODEL_NAME='sentence-transformers/all-MiniLM-L6-v2'
    FROM='f'
);
INSERT INTO t (id, f, m) VALUES (1, 'a', (1));
SELECT f, m FROM t;
drop table t;

